```ts
describe('createLocalStore', () => {
  it('falls back to the default when localStorage has invalid JSON', () => {
    localStorage.setItem('k', 'not json')
    expect(createLocalStore('k', { a: 1 }).get()).toEqual({ a: 1 })
  })
  it('merges stored partial state over defaults', () => {
    localStorage.setItem('k', JSON.stringify({ a: 2 }))
    expect(createLocalStore('k', { a: 1, b: 2 }).get()).toEqual({ a: 2, b: 2 })
  })
  it('keeps working in-memory when localStorage.setItem throws (e.g. private mode/quota)', () => {
    const store = createLocalStore('k', { a: 1 })
    const spy = vi.spyOn(Storage.prototype, 'setItem').mockImplementation(() => { throw new Error('quota') })
    expect(() => store.set({ a: 2 })).not.toThrow()
    expect(store.get()).toEqual({ a: 2 })
    spy.mockRestore()
  })
  it('notifies subscribed listeners on set, and stops after unsubscribe', () => {
    const store = createLocalStore('k', { a: 1 })
    const listener = vi.fn()
    const unsub = store.subscribe(listener)
    store.set({ a: 2 })
    unsub()
    store.set({ a: 3 })
    expect(listener).toHaveBeenCalledTimes(1)
  })
})
```

